const defaults = $('Load Global Settings').first()?.json ?? {};
const request = $('Send Team Captain Contact Lists Webhook').first()?.json ?? $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const parseJsonObject = (value) => {
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
    } catch {
      return {};
    }
  }
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
};
const query = parseJsonObject(request.query);
const body = parseJsonObject(request.body);
const modeCandidates = [body.delivery_mode, body.deliveryMode, request.delivery_mode, request.deliveryMode, query.delivery_mode, query.deliveryMode, query.mode, defaults.default_delivery_mode];
const normalizedMode = String(modeCandidates.find((value) => clean(value) !== '') ?? 'test').trim().toLowerCase();
const deliveryMode = normalizedMode === 'production' ? 'production' : 'test';
const recipientCandidates = [body.test_recipient, body.testRecipient, request.test_recipient, request.testRecipient, query.test_recipient, query.testRecipient, defaults.default_test_recipient];
const testRecipient = String(recipientCandidates.find((value) => clean(value) !== '') ?? 'steve.short@gmail.com').trim();
const category = clean(body.category) || clean(query.category) || 'ALL';
const scope = clean(body.scope) || clean(query.scope) || 'own_next_reserves';
const baseDir = clean(body.base_dir) || clean(query.base_dir) || '/home/node/.n8n-files/teams-mailout/current';
const normalizeJob = (value) => {
  if (!value) return null;
  if (typeof value === 'string') {
    try { return normalizeJob(JSON.parse(value)); } catch { return null; }
  }
  if (Array.isArray(value) || typeof value !== 'object') return null;
  const job = value;
  if (!clean(job.team_name) || !clean(job.own_pdf) || !clean(job.next_pdf) || !clean(job.reserves_pdf)) return null;
  return job;
};
const rawJobs = [
  ...(Array.isArray(body.jobs) ? body.jobs : []),
  ...(Array.isArray(request.jobs) ? request.jobs : []),
  ...(Array.isArray(query.jobs) ? query.jobs : []),
  body.job,
  request.job,
  query.job,
].filter((value) => value !== undefined && value !== null);
const jobs = rawJobs.map(normalizeJob).filter(Boolean);
// Filter jobs by category if specified
let filteredJobs = jobs;
if (category !== 'ALL') {
  filteredJobs = jobs.filter(j => (j.section || '').toLowerCase() === category.toLowerCase());
}

// Filter jobs by scope
if (scope === 'own_only') {
  // Keep only own team + reserves (remove next team)
  filteredJobs = filteredJobs.map(j => ({ ...j, next_pdf: '', next_team_name: '' }));
} else if (scope === 'own_reserves') {
  // Keep own team + reserves, no next team
  filteredJobs = filteredJobs.map(j => ({ ...j, next_pdf: '', next_team_name: '' }));
}
// 'own_next_reserves' and 'all_category' keep all attachments as-is

const errorMessage = filteredJobs.length ? '' : 'No mailout jobs match the selected filters';
return [{ json: { base_dir: baseDir, category: category, scope: scope,  sender_name: defaults.email_sender_name || 'Steve Short', reply_to: defaults.email_reply_to || 'members.avondaleltc@gmail.com', template_key: 'team_captain_contact_lists', signature_template_key: defaults.email_signature_template_key || 'signature', delivery_mode: deliveryMode, test_recipient: testRecipient, jobs: filteredJobs, error_message: errorMessage } }];

const input = $input.first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `with main_template as (
  select template_key, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(input.template_key || 'team_captain_contact_lists')}
    and is_active = true
    and template_type = 0
  order by id desc
  limit 1
), signature_template as (
  select template_key, subject_template, text_template, html_template
  from public.email_templates
  where template_key = ${sqlLiteral(input.signature_template_key || 'signature')}
    and is_active = true
    and template_type = 2
  order by id desc
  limit 1
)
select
  main_template.template_key,
  main_template.subject_template,
  main_template.text_template,
  main_template.html_template,
  signature_template.template_key as signature_template_key,
  signature_template.text_template as signature_text_template,
  signature_template.html_template as signature_html_template
from main_template
left join signature_template on true;`;
return [{ json: { ...input, sql } }];

const config = $('Resolve Request').first()?.json ?? {};
const template = $('Load Signature Template').first()?.json ?? {};
const jobs = Array.isArray(config.jobs) ? config.jobs : [];
const sendableJobs = jobs.filter((job) => Boolean(job?.can_send) && String(job?.captain_email ?? '').trim() !== '');
if (!sendableJobs.length) {
  return [{ json: { error_message: 'No sendable captain jobs found', job_count: jobs.length, delivery_mode: config.delivery_mode } }];
}
if (!template.template_key) {
  throw new Error(`Email template ${config.template_key || 'team_captain_contact_lists'} was not found`);
}
const templateText = String(template.text_template ?? '').trim();
const signatureText = String(template.signature_text_template ?? '').trim();
const joinPath = (baseDir, fileName) => `${String(baseDir ?? '').replace(/\/$/, '')}/${String(fileName ?? '').replace(/^\//, '')}`;
const firstNameOf = (name) => String(name ?? '').trim().split(/\s+/)[0] || 'Captain';
const applyTokens = (value, tokenMap) => {
  let rendered = String(value ?? '');
  for (const [token, replacement] of Object.entries(tokenMap)) {
    rendered = rendered.split(token).join(String(replacement ?? ''));
  }
  return rendered.trim();
};
return sendableJobs.map((job) => {
  const captainName = String(job.captain_name ?? '').trim();
  const captainEmail = String(job.captain_email ?? '').trim();
  const firstName = firstNameOf(captainName);
  const nextTeamName = String(job.next_team_name ?? 'Reserves').trim() || 'Reserves';
  const attachmentLines = [
    `- your team: ${job.team_name}`,
    nextTeamName === 'Reserves' ? '- reserves' : `- the next team down: ${nextTeamName}`,
  ];
  if (nextTeamName !== 'Reserves') {
    attachmentLines.push('- reserves');
  }
  const tokenMap = {
    '{{$json.first_name}}': firstName,
    '{{$json.captain_name}}': captainName,
    '{{$json.team_name}}': String(job.team_name ?? ''),
    '{{$json.next_team_name}}': nextTeamName,
    '{{$json.section}}': String(job.section ?? ''),
    '{{$json.source_doc}}': String(job.source_doc ?? ''),
    '{{$json.attachment_list}}': attachmentLines.join('\n'),
    '{{first_name}}': firstName,
    '{{captain_name}}': captainName,
    '{{team_name}}': String(job.team_name ?? ''),
    '{{next_team_name}}': nextTeamName,
    '{{section}}': String(job.section ?? ''),
    '{{source_doc}}': String(job.source_doc ?? ''),
    '{{attachment_list}}': attachmentLines.join('\n'),
  };
  const renderedBody = applyTokens(templateText, tokenMap);
  const renderedSignature = applyTokens(signatureText, tokenMap);
  const composed = [renderedBody, renderedSignature].filter(Boolean).join('\n\n').trim();
  const isTestMode = config.delivery_mode !== 'production';
  const finalMessage = isTestMode
    ? `${composed}\n\n---\nTEST MODE\nIntended recipient: ${captainEmail}`
    : composed;
  return {
    json: {
      section: job.section,
      source_doc: job.source_doc,
      team_name: job.team_name,
      next_team_name: nextTeamName,
      captain_name: captainName,
      intended_recipient: captainEmail,
      actual_recipient: isTestMode ? config.test_recipient : captainEmail,
      own_pdf: job.own_pdf,
      next_pdf: job.next_pdf,
      reserves_pdf: job.reserves_pdf,
      own_pdf_path: joinPath(config.base_dir, job.own_pdf),
      next_pdf_path: joinPath(config.base_dir, job.next_pdf),
      reserves_pdf_path: joinPath(config.base_dir, job.reserves_pdf),
      sender_name: config.sender_name,
      reply_to: config.reply_to,
      delivery_mode: config.delivery_mode,
      template_key: template.template_key,
      signature_template_key: template.signature_template_key || config.signature_template_key || 'signature',
      rendered_subject: applyTokens(template.subject_template ?? 'Avondale team contact lists: {{$json.team_name}}', tokenMap),
      rendered_message: finalMessage,
      email_type: 'text'
    }
  };
});

const sourceJson = { ...($('Build Send Items').item.json ?? {}) };
const attachment0 = $('Read Own Attachment').item.binary?.attachment_0;
const attachment1 = $('Read Next Attachment').item.binary?.attachment_1;
const attachment2 = $('Read Reserves Attachment').item.binary?.attachment_2;
if (!attachment0 || !attachment1 || !attachment2) {
  throw new Error('Missing one or more attachment binaries');
}
return {
  json: sourceJson,
  binary: {
    attachment_0: attachment0,
    attachment_1: attachment1,
    attachment_2: attachment2,
  },
};

const sourceItems = $('Build Send Items').all().map((item) => item.json ?? {});
return [{
  json: {
    message: `Sent ${sourceItems.length} captain email(s) in ${sourceItems[0]?.delivery_mode ?? 'test'} mode`,
    sent_count: sourceItems.length,
    delivery_mode: sourceItems[0]?.delivery_mode ?? 'test',
    sent: sourceItems.map((item) => ({
      captain_name: item.captain_name,
      team_name: item.team_name,
      actual_recipient: item.actual_recipient,
      intended_recipient: item.intended_recipient
    }))
  }
}];
